"use client";
import { useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const points=[['North',18,16],['Center',48,46],['South',76,70]];
export default function PinpointLedgerField(){const [active,setActive]=useState(1);const reduced=useReducedMotion();return <section className="w-full max-w-sm overflow-hidden rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><p className="text-xs font-bold uppercase tracking-[.14em] text-[#4a4a4f]">pinpoint ledger</p><div aria-hidden className="relative mt-4 h-32 rounded-[18px] bg-[#f4f5f6]" style={{backgroundImage:'radial-gradient(#d4d4d8 1px,transparent 1px)',backgroundSize:'18px 18px'}}><motion.i animate={{left:`${points[active][1]}%`,top:`${points[active][2]}%`}} transition={reduced?{duration:.12}:{type:"spring",stiffness:280,damping:25}} className="absolute h-3 w-3 -translate-x-1/2 -translate-y-1/2 rounded-full bg-[#f59e0b]"/></div><div aria-label="Choose coordinate" className="mt-3 flex flex-wrap gap-2">{points.map((point,i)=><motion.button key={point[0]} type="button" aria-pressed={active===i} onClick={()=>setActive(i)} whileHover={reduced?undefined:{y:-2}} whileTap={reduced?undefined:{y:1}} className="min-h-11 rounded-xl border border-[#ececee] px-3 text-sm font-bold text-[#111] outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">{point[0]}</motion.button>)}</div><p aria-live="polite" className="mt-3 text-xs text-[#4a4a4f]">Active coordinate: {points[active][0]}.</p></section>}
